function u(t){if(t==null)return null;if(t instanceof Date)return Number.isNaN(t.getTime())?null:t;if(typeof t=="number"&&Number.isFinite(t)){const n=new Date(t);return Number.isNaN(n.getTime())?null:n}if(typeof t=="string"&&t.trim()){const n=new Date(t);return Number.isNaN(n.getTime())?null:n}const e=t;if(typeof e.toDate=="function"){const n=e.toDate();return Number.isNaN(n.getTime())?null:n}if(typeof e.toMillis=="function"){const n=new Date(e.toMillis());return Number.isNaN(n.getTime())?null:n}return null}function f(t){const e=u(t);if(!e)return"—";const n=String(e.getDate()).padStart(2,"0"),r=String(e.getMonth()+1).padStart(2,"0"),i=e.getFullYear(),o=String(e.getHours()).padStart(2,"0"),s=String(e.getMinutes()).padStart(2,"0");return`${n}/${r}/${i} à ${o}:${s}`}export{f};
